49	/// A class to encapsulate construction axes of an Tensor.  TensorOptions was
50	/// designed to support the Python style API for specifying construction options
51	/// on factory functions, e.g.,
52	///
53	///     torch.zeros(2, 3, dtype=torch.int32)
54	///
55	/// Because C++ doesn't natively support keyword arguments, there must be
56	/// another way of specifying keyword-like arguments.  TensorOptions is a
57	/// builder class which can be used to construct this "dictionary" of keyword
58	/// arguments: functions which support TensorOptions conventionally take this
59	/// argument optionally as their last argument.
60	///
61	/// WARNING: In PyTorch, there are `torch::` variants of factory functions,
62	/// e.g., torch::zeros for at::zeros.  These return Variables (while the
63	/// stock ATen functions return plain Tensors).  If you mix these functions
64	/// up, you WILL BE SAD.
65	///
66	/// Rather than use the constructor of this class directly, you should prefer to
67	/// use the constructor functions, and then chain setter methods on top of them.
68	///
69	///     at::device(at::kCUDA).dtype(kInt)
70	///     at::dtype(at::kInt)
71	///
72	/// Additionally, anywhere a TensorOptions is expected, you can directly
73	/// pass at::kCUDA / at::kInt, and it will implicitly convert to a
74	/// TensorOptions.
75	///
76	/// Here are some recommended ways to create a 2x2 tensor of zeros
77	/// with certain properties.  These all *implicitly* make use of
78	/// TensorOptions, even if they don't mention the class explicitly:
79	///
80	///     at::zeros({2,2}, at::kCUDA);
81	///     at::zeros({2,2}, at::kLong);
82	///     at::zeros({2,2}, at::device(at::kCUDA).dtype(at::kLong()));
83	///     at::zeros({2,2}, at::device({at::kCUDA, 1})); // place on device 1
84	///     at::zeros({2,2}, at::requires_grad());
85	///
86	
87	/// NOTE [ TensorOptions Constructors ]
88	///
89	/// TensorOptions is like a dictionary with entries from the set:
90	/// {requires_grad, device, dtype, layout}, where each entry may be
91	/// unspecified (i.e., is optional). It is used to specify the properties of
92	/// tensors in many places both in C++ internal and API, e.g., tensor factory
93	/// methods like `at::empty({10}, options)`, tensor conversions like
94	/// `tensor.to(...)`, etc.
95	///
96	/// To provide a simple API that is consistent with Python, where one can do
97	/// `torch.empty(sizes, X)` with `X` being a `torch.device`, `torch.dtype`, or a
98	/// `torch.layout`, we want TensorOptions to be implicitly convertible from
99	/// `ScalarType dtype`, `Layout layout` and `Device device`. Therefore, we have
100	/// three implicit constructors from each of these three types.
101	///
102	/// This is sufficient for `ScalarType` and `Layout` as they are simple Enum
103	/// classes. However, `Device` is an ordinary class with implicit constructors
104	/// `Device(DeviceType, DeviceIndex = -1)` and `Device(std::string)` to be
105	/// consistent with Python API, where strings are treated as equivalent with a
106	/// `torch.device` object (e.g., "cuda:1" can be passed to everywhere a
107	/// `torch.device("cuda:1")` is accepted). To support the syntax
108	/// `at::empty({10}, {kCUDA, 1})` and `tensor.to(kCUDA)`, we need to make sure
109	/// that `TensorOptions` is implicitly constructible with any arguments that a
110	/// `Device` can constructed from. So we have,
111	///
112	///    /* implicit */ TensorOptions(T&& device) : TensorOptions() {
113	///      this->set_device(device);
114	///    }
115	///
116	///    template <typename... Args,
117	///             typename = std::enable_if_t<std::is_constructible<Device,
118	///             Args&&...>::value>>
119	///    /* implicit */  TensorOptions(Args&&... args)
120	///     : TensorOptions(Device(std::forward<Args>(args)...)) {}
121	///
122	///
123	/// But this will be problematic. Consider this: `TensorOptions({kCUDA, 1})`.
124	/// Compiler will complain about ambiguity between the copy constructor and the
125	/// `Device` constructor because `{kCUDA, 1}` can be converted to both a
126	/// `TensorOption` and a `Device`.
127	///
128	/// To get around this, we templatize the `Device` constructor. Since overload
129	/// resolution is done before template resolution, our problem is solved.
130	
131	DispatchKey computeDispatchKey(
132	    std::optional<ScalarType> dtype,
133	    std::optional<Layout> layout,
134	    std::optional<Device> device);
135	
136	struct C10_API TensorOptions {
137	  // NOLINTNEXTLINE(modernize-use-equals-default)
138	  TensorOptions() noexcept {}
139	
140	  /// Constructs a `TensorOptions` object with the given layout.
141	  /* implicit */ TensorOptions(Layout layout) : TensorOptions() {
142	    this->set_layout(layout);
143	  }
144	
145	  /// Constructs a `TensorOptions` object with the given device.
146	  /// See NOTE [ TensorOptions Constructors ] on why this is templatized.
147	  template <
148	      typename T,
149	      typename = std::enable_if_t<std::is_same_v<std::decay_t<T>, Device>>>
150	  /* implicit */ TensorOptions(T&& device) : TensorOptions() {
151	    this->set_device(std::forward<T>(device));
152	  }
153	
154	  /// Constructs a `TensorOptions` object from arguments allowed in `Device`
155	  /// constructors.
156	  ///
157	  /// See NOTE [ TensorOptions Constructors ].
158	  ///
159	  /// NB: Ideally we only allow implicit constructors here. But there is no easy
160	  ///     way to detect them. So we have this one that allows explicit
161	  ///     constructors too.
162	  template <
163	      typename... Args,
164	      typename = std::enable_if_t<std::is_constructible_v<Device, Args&&...>>>
165	  /* implicit */ TensorOptions(Args&&... args)
166	      : TensorOptions(Device(std::forward<Args>(args)...)) {}
167	
168	  /// Constructs a `TensorOptions` object with the given dtype.
169	  /* implicit */ TensorOptions(caffe2::TypeMeta dtype) : TensorOptions() {
170	    this->set_dtype(dtype);
171	  }
172	
173	  /// legacy constructor to support ScalarType
174	  /* implicit */ TensorOptions(ScalarType dtype) : TensorOptions() {
175	    this->set_dtype(dtype);
176	  }
177	
178	  /// Constructs a `TensorOptions` object with the given memory format.
179	  /* implicit */ TensorOptions(MemoryFormat memory_format) : TensorOptions() {
180	    set_memory_format(memory_format);
181	  }
182	
183	  /// Return a copy of `TensorOptions` with `device` set to the given one, or
184	  /// cleared if `device` is `nullopt`.
185	  [[nodiscard]] TensorOptions device(
186	      std::optional<Device> device) const noexcept {
187	    TensorOptions r = *this;
188	    r.set_device(device);
189	    return r;
190	  }
191	
192	  /// Return a copy of `TensorOptions` with `device` set to the given one.
193	  /// (This overload ensures that variadic template std::optional constructor
194	  /// for Device work correctly.)
195	  template <typename... Args>
196	  [[nodiscard]] TensorOptions device(Args&&... args) const noexcept {
197	    return device(
198	        std::optional<Device>(std::in_place, std::forward<Args>(args)...));
199	  }
200	
201	  /// Return a copy of `TensorOptions`, but with device set to CUDA, and the
202	  /// device index set to the given one.
203	  ///
