212	  [[nodiscard]] TensorOptions dtype(
213	      std::optional<caffe2::TypeMeta> dtype) const noexcept {
214	    TensorOptions r = *this;
215	    r.set_dtype(dtype);
216	    return r;
217	  }
218	
219	  // legacy function to support ScalarType
220	  [[nodiscard]] TensorOptions dtype(
221	      std::optional<ScalarType> dtype) const noexcept {
222	    TensorOptions r = *this;
223	    r.set_dtype(dtype);
224	    return r;
225	  }
