251	  /// Sets the `pinned_memory` property on the `TensorOptions`.
252	  [[nodiscard]] TensorOptions pinned_memory(
253	      std::optional<bool> pinned_memory) const noexcept {
254	    TensorOptions r = *this;
255	    r.set_pinned_memory(pinned_memory);
256	    return r;
257	  }
