289	  caffe2::TypeMeta dtype() const noexcept {
290	    return dtype_or_default(dtype_opt());
291	  }
292	
293	  /// Returns whether the dtype is specified.
294	  bool has_dtype() const noexcept {
295	    return has_dtype_;
296	  }
297	
