314	  /// Returns the layout of the `TensorOptions`, or `std::nullopt` if
315	  /// layout is not specified.
316	  std::optional<Layout> layout_opt() const noexcept {
317	    return has_layout_ ? std::make_optional(layout_) : std::nullopt;
318	  }
319	
320	  /// Returns the `requires_grad` property of the `TensorOptions`.
321	  bool requires_grad() const noexcept {
322	    return has_requires_grad_ ? requires_grad_ : false;
323	  }
324	
325	  /// Returns whether the `requires_grad` is specified.
326	  bool has_requires_grad() const noexcept {
327	    return has_requires_grad_;
328	  }
329	
330	  /// Returns the `requires_grad` property of the `TensorOptions`, or
331	  /// `std::nullopt` if `requires_grad` is not specified.
332	  std::optional<bool> requires_grad_opt() const noexcept {
333	    return has_requires_grad_ ? std::make_optional(requires_grad_)
334	                              : std::nullopt;
335	  }
336	
337	  /// Returns the `pinned_memory` property of the `TensorOptions`.
338	  bool pinned_memory() const noexcept {
339	    return pinned_memory_or_default(pinned_memory_opt());
340	  }
341	
342	  /// Returns whether the `pinned_memory` is specified.
343	  bool has_pinned_memory() const noexcept {
344	    return has_pinned_memory_;
345	  }
346	
347	  /// Returns if the layout is sparse
348	  bool is_sparse() const {
349	    return layout_ == c10::Layout::Sparse;
350	  }
351	
352	  /// Returns if the layout is sparse CSR, deprecated, use
353	  /// is_sparse_compressed() instead
354	  bool is_sparse_csr() const {
355	    return layout_ == c10::Layout::SparseCsr;
356	  }
357	
358	  bool is_sparse_compressed() const {
359	    return layout_ == c10::Layout::SparseCsr ||
360	        layout_ == c10::Layout::SparseCsc ||
361	        layout_ == c10::Layout::SparseBsr || layout_ == c10::Layout::SparseBsc;
362	  }
363	
364	  // For compatibility with legacy tensor.type() comparisons
365	  bool type_equal(const TensorOptions& other) const {
366	    return computeDispatchKey() == other.computeDispatchKey() &&
367	        typeMetaToScalarType(dtype_) == typeMetaToScalarType(other.dtype());
368	  }
369	
370	  /// Returns the `pinned_memory` property of the `TensorOptions`, or
371	  /// `std::nullopt` if `pinned_memory` is not specified.
372	  std::optional<bool> pinned_memory_opt() const noexcept {
373	    return has_pinned_memory_ ? std::make_optional(pinned_memory_)
374	                              : std::nullopt;
375	  }
376	
377	  /// Returns whether the `memory_layout` is specified
378	  bool has_memory_format() const noexcept {
379	    return has_memory_format_;
380	  }
381	
382	  // NB: memory_format() getter is PURPOSELY not defined, as the default
383	  // behavior of memory_format varies from function to function.
384	
385	  /// Returns the `memory_layout` property of `TensorOptions, or
386	  /// `std::nullopt` if `memory_format` is not specified.
387	  std::optional<MemoryFormat> memory_format_opt() const noexcept {
388	    return has_memory_format_ ? std::make_optional(memory_format_)
389	                              : std::nullopt;
390	  }
391	
392	  // Resolves the ATen backend specified by the current construction axes.
393	  // TODO: Deprecate this
394	  Backend backend() const {
395	    return at::dispatchKeyToBackend(computeDispatchKey());
396	  }
397	
398	  /// Return the right-biased merge of two TensorOptions.  This has the
399	  /// effect of overwriting settings from self with specified options
400	  /// of options.
401	  ///
402	  /// NB: This merging operation does NOT respect device merges.
403	  /// For example, if you device({kCUDA, 1}).merge_in(kCUDA)
404	  /// you will get kCUDA in the end!  Functions like Tensor.new_empty
405	  /// ensure the right device is selected anyway by way of a
406	  /// device guard.
407	  ///
408	  TensorOptions merge_in(TensorOptions options) const noexcept {
409	    TensorOptions merged = *this;
410	    if (options.has_device())
411	      merged.set_device(options.device_opt());
412	    if (options.has_dtype())
413	      merged.set_dtype(options.dtype_opt());
414	    if (options.has_layout())
415	      merged.set_layout(options.layout_opt());
416	    // NB: requires grad is right biased; not a logical AND/OR!
417	    if (options.has_requires_grad())
418	      merged.set_requires_grad(options.requires_grad_opt());
419	    if (options.has_pinned_memory())
420	      merged.set_pinned_memory(options.pinned_memory_opt());
421	    if (options.has_memory_format())
422	      merged.set_memory_format(options.memory_format_opt());
423	    return merged;
424	  }
425	
426	  // TODO remove after TensorOptions rationalization
427	  TensorOptions merge_memory_format(
428	      std::optional<MemoryFormat> optional_memory_format) const noexcept {
429	    TensorOptions merged = *this;
430	    if (optional_memory_format.has_value()) {
431	      merged.set_memory_format(optional_memory_format);
432	    }
433	    return merged;
434	  }
435	
436	  // INVARIANT: computeDispatchKey returns only the subset of dispatch keys for
437	  // which dispatchKeyToBackend is injective, if it is defined at all  (for
438	  // the most part, this just means that this function never returns an
439	  // Autograd key)
440	  DispatchKey computeDispatchKey() const {
441	    return c10::computeDispatchKey(
442	        optTypeMetaToScalarType(dtype_opt()), layout_opt(), device_opt());
443	  }
