445	 private:
446	  // These methods are currently private because I'm not sure if it's wise
447	  // to actually publish them.  They are methods because I need them in
448	  // the constructor and the functional API implementation.
449	  //
450	  // If you really, really need it, you can make these public, but check if you
451	  // couldn't just do what you need with the functional API.  Similarly, these
452	  // methods are not chainable, because if you wanted chaining, you probably
453	  // want to use the functional API instead.  (It's probably OK to make
454	  // these chainable, because these functions are all explicitly annotated
455	  // with a ref-qualifier, the trailing &, that makes them illegal to call
456	  // on temporaries.)
457	
458	  /// Mutably set the device of `TensorOptions`.
459	  void set_device(std::optional<Device> device) & noexcept {
460	    if (device) {
461	      device_ = *device;
462	      has_device_ = true;
463	    } else {
464	      has_device_ = false;
465	    }
466	  }
467	
468	  /// Mutably set the dtype of `TensorOptions`.
469	  void set_dtype(std::optional<caffe2::TypeMeta> dtype) & noexcept {
470	    if (dtype) {
471	      dtype_ = *dtype;
472	      has_dtype_ = true;
473	    } else {
474	      has_dtype_ = false;
475	    }
476	  }
477	
478	  // legacy function to support ScalarType
479	  void set_dtype(std::optional<ScalarType> dtype) & noexcept {
480	    if (dtype) {
481	      dtype_ = scalarTypeToTypeMeta(*dtype);
482	      has_dtype_ = true;
483	    } else {
484	      has_dtype_ = false;
485	    }
486	  }
487	
488	  /// Mutably set the layout of `TensorOptions`.
489	  void set_layout(std::optional<Layout> layout) & noexcept {
490	    if (layout) {
491	      layout_ = *layout;
492	      has_layout_ = true;
493	    } else {
494	      has_layout_ = false;
495	    }
496	  }
497	
498	  /// Mutably set the `requires_grad` property of `TensorOptions`.
499	  void set_requires_grad(std::optional<bool> requires_grad) & noexcept {
500	    if (requires_grad) {
501	      requires_grad_ = *requires_grad;
502	      has_requires_grad_ = true;
503	    } else {
504	      has_requires_grad_ = false;
505	    }
506	  }
507	
508	  /// Mutably set the `pinned_memory` property of `TensorOptions`.
509	  void set_pinned_memory(std::optional<bool> pinned_memory) & noexcept {
510	    if (pinned_memory) {
511	      pinned_memory_ = *pinned_memory;
512	      has_pinned_memory_ = true;
513	    } else {
514	      has_pinned_memory_ = false;
515	    }
516	  }
517	
518	  /// Mutably set the `memory_Format` property of `TensorOptions`.
519	  void set_memory_format(std::optional<MemoryFormat> memory_format) & noexcept {
520	    if (memory_format) {
521	      memory_format_ = *memory_format;
522	      has_memory_format_ = true;
523	    } else {
524	      has_memory_format_ = false;
525	    }
526	  }
527	
528	  // WARNING: If you edit TensorOptions to add more options, you
529	  // may need to adjust the implementation of Tensor::options.
530	  // The criteria for whether or not Tensor::options must be adjusted
531	  // is whether or not the new option you added should preserved
532	  // by functions such as empty_like(); if it should be preserved,
533	  // you must adjust options().
534	  //
535	  // TODO: MemoryFormat is not implemented in this way
536	
537	  // NB: We didn't use std::optional here, because then we can't pack
538	  // the has_***_ boolean fields.
539	
540	  Device device_ = at::kCPU; // 16-bit
541	  caffe2::TypeMeta dtype_ = caffe2::TypeMeta::Make<float>(); // 16-bit
542	  Layout layout_ = at::kStrided; // 8-bit
543	  MemoryFormat memory_format_ = MemoryFormat::Contiguous; // 8-bit
544	
545	  // Bitmask required here to get this to fit inside 32 bits (or even 64 bits,
546	  // for that matter)
547	
548	  bool requires_grad_ : 1 = false;
549	  bool pinned_memory_ : 1 = false;
550	
551	  bool has_device_ : 1 = false;
552	  bool has_dtype_ : 1 = false;
553	  bool has_layout_ : 1 = false;
554	  bool has_requires_grad_ : 1 = false;
555	  bool has_pinned_memory_ : 1 = false;
556	  bool has_memory_format_ : 1 = false;
557	};
558	
559	// We should aspire to fit in one machine-size word; but a size greater than two
560	// words is too much.  (We are doing terribly on 32-bit archs, where we require
561	// three machine size words to store tensor options.  Eek!)
562	static_assert(
563	    sizeof(TensorOptions) <= sizeof(int64_t) * 2,
564	    "TensorOptions must fit in 128-bits");
565	
566	/// Convenience function that returns a `TensorOptions` object with the `dtype`
