622	// This is intended to be a centralized location by which we can determine
623	// what an appropriate DispatchKey for a tensor is.
624	inline DispatchKey computeDispatchKey(
625	    std::optional<ScalarType> dtype,
626	    std::optional<Layout> layout,
627	    std::optional<Device> device) {
628	  const auto layout_ = layout_or_default(layout);
629	  const auto device_ = device_or_default(device);
630	  switch (layout_) {
631	    case Layout::Jagged:
632	    case Layout::Strided: {
633	      const auto dtype_ = dtype_or_default(dtype);
634	      switch (device_.type()) {
635	#define DO_CASE(device, _)                   \
636	  case c10::DeviceType::device: {            \
637	    if (isQIntType(dtype_)) {                \
638	      return DispatchKey::Quantized##device; \
639	    }                                        \
640	    return DispatchKey::device;              \
641	  }
642	        C10_FORALL_BACKEND_DEVICE_TYPES(DO_CASE, unused)
643	#undef DO_CASE
644	        case c10::DeviceType::FPGA:
645	          return DispatchKey::FPGA;
646	        case c10::DeviceType::MAIA:
647	          return DispatchKey::MAIA;
648	        case c10::DeviceType::Vulkan:
649	          return DispatchKey::Vulkan;
650	        case c10::DeviceType::Metal:
651	          return DispatchKey::Metal;
652	        case c10::DeviceType::MKLDNN:
653	          TORCH_CHECK_NOT_IMPLEMENTED(
654	              false,
655	              "The 'mkldnn' device type is deprecated and cannot be used "
656	              "to allocate dense tensors. Please use a supported device type "
657	              "instead.");
658	        case c10::DeviceType::OPENGL:
659	        case c10::DeviceType::OPENCL:
660	        case c10::DeviceType::IDEEP:
661	          TORCH_INTERNAL_ASSERT(
662	              0,
663	              "This is a grandfathered Caffe2 device type ",
664	              device_.type(),
665	              ", it shouldn't ever convert to a DispatchKey.  File a bug describing what you were doing if you think this is in error.");
666	        default:
667	          TORCH_CHECK_NOT_IMPLEMENTED(
668	              false,
669	              "Unsupported device type for dense layout: ",
670	              device_.type());
671	      }
672	    }
673	    case Layout::Sparse:
674	      switch (device_.type()) {
675	#define DO_CASE(device, _)              \
676	  case c10::DeviceType::device: {       \
677	    return DispatchKey::Sparse##device; \
678	  }
679	        C10_FORALL_BACKEND_DEVICE_TYPES(DO_CASE, unused)
680	#undef DO_CASE
681	        default:
682	          TORCH_CHECK_NOT_IMPLEMENTED(
683	              false,
684	              "Unsupported device type for sparse layout: ",
685	              device_.type());
686	      }
687	    case Layout::Mkldnn:
688	      switch (device_.type()) {
689	        case c10::DeviceType::CPU:
690	          return DispatchKey::MkldnnCPU;
691	        default:
692	          TORCH_CHECK_NOT_IMPLEMENTED(
693	              false,
694	              "Unsupported device type for mkldnn layout: ",
695	              device_.type());
696	      }
697	    case Layout::SparseCsr:
698	    case Layout::SparseCsc:
699	    case Layout::SparseBsr:
700	    case Layout::SparseBsc:
701	      switch (device_.type()) {
702	#define DO_CASE(device, _)                 \
703	  case c10::DeviceType::device: {          \
704	    return DispatchKey::SparseCsr##device; \
705	  }
706	        C10_FORALL_BACKEND_DEVICE_TYPES(DO_CASE, unused)
707	#undef DO_CASE
708	        default:
709	          TORCH_CHECK_NOT_IMPLEMENTED(
710	              false,
711	              "Unsupported device type for ",
712	              layout_,
713	              " layout: ",
714	              device_.type());
715	      }
716	    default:
717	      TORCH_CHECK(false, "Unsupported layout: ", layout_);
718	  }
719	}
720	
721	inline Layout dispatchKeyToLayout(DispatchKey dispatch_key) {
722	  switch (dispatch_key) {
723	#define DO_CASE(bc, _) case DispatchKey::Sparse##bc:
724	    C10_FORALL_BACKEND_COMPONENTS(DO_CASE, unused)
725	#undef DO_CASE
726	    return Layout::Sparse;
727	#define DO_CASE(bc, _) case DispatchKey::SparseCsr##bc:
728	    C10_FORALL_BACKEND_COMPONENTS(DO_CASE, unused)
729	#undef DO_CASE
730	    TORCH_CHECK(
731	        false, "Cannot map DispatchKey ", dispatch_key, " to a unique layout.");
732	    case DispatchKey::MkldnnCPU:
733	      return Layout::Mkldnn;
734	    default:
735	      return Layout::Strided;
736	  }
737	}
738	
739	inline c10::DeviceType dispatchKeyToDeviceType(DispatchKey dispatch_key) {
740	  switch (dispatch_key) {
741	    // stuff that's real
742	#define DO_CASE(suffix, prefix)     \
743	  case DispatchKey::prefix##suffix: \
744	    return c10::DeviceType::suffix;
745	#define DO_CASES(_, prefix) C10_FORALL_BACKEND_DEVICE_TYPES(DO_CASE, prefix)
746	    C10_FORALL_FUNCTIONALITY_KEYS(DO_CASES)
747	#undef DO_CASES
748	#undef DO_CASE
749	
750	    case DispatchKey::MkldnnCPU:
751	      return c10::DeviceType::CPU;
752	    case DispatchKey::Vulkan:
753	      return c10::DeviceType::Vulkan;
754	
755	    case DispatchKey::MAIA:
756	      return c10::DeviceType::MAIA;
757	    default:
758	      TORCH_CHECK(
759	          false,
760	          "DispatchKey ",
761	          dispatch_key,
762	          " doesn't correspond to a device");
763	  }
764	}
765	
766	inline TensorOptions dispatchKeyToTensorOptions(DispatchKey dispatch_key) {
767	  return TensorOptions()
768	      .layout(dispatchKeyToLayout(dispatch_key))
769	      .device(dispatchKeyToDeviceType(dispatch_key));
770	}
771	
772	namespace detail {
773	inline bool backend_supports_empty_operator(const TensorOptions& options) {
774	  // Quantized backends don't support at::empty().
775	  // They have separate operators like at::empty_quantized() that take in
776	  // extra information about how to quantize the tensor.
777	  return !isQIntType(typeMetaToScalarType(options.dtype()));
778	}
779	
780	} // namespace detail
781	
782	} // namespace c10
