266	  // disallowed.
267	  if (isComplexType(from) && !isComplexType(to)) {
268	    return false;
269	  }
270	  // We disallow float -> integral, e.g., int_tensor *= float is disallowed.
271	  if (isFloatingType(from) && isIntegralType(to, false)) {
272	    return false;
273	  }
274	
275	  // Treat bool as a distinct "category," to be consistent with type promotion
276	  // rules (e.g. `bool_tensor + 5 -> int64_tensor`). If `5` was in the same
277	  // category as `bool_tensor`, we would not promote. Differing categories
278	  // implies `bool_tensor += 5` is disallowed.
279	  //
280	  // NB: numpy distinguishes "unsigned" as a category to get the desired
281	  // `bool_tensor + 5 -> int64_tensor` behavior. We don't, because:
282	  // * We don't want the performance hit of checking the runtime sign of
283	  // Scalars.
284	  // * `uint8_tensor + 5 -> int64_tensor` would be undesirable.
285	  if (from != ScalarType::Bool && to == ScalarType::Bool) {
